
import { SmileOutlined, DownOutlined } from "@ant-design/icons-vue";
import { defineComponent } from "vue";
import config from "../../../server/http/config";
import { DownLoadSample } from "../../../utils/DownLoad";
import base from "../../../utils/base64";
const columns = [
  {
    title: "样品名称",
    dataIndex: "sampleName",
    key: "sampleName",
  },
  {
    title: "生产厂家",
    key: "manufacturer",
    dataIndex: "manufacturer",
  },
  {
    title: "规格/等级",
    key: "specs",
    dataIndex: "specs",
  },
  {
    title: "收样人",
    key: "inspector",
    dataIndex: "inspector",
  },

  {
    title: "代表批量",
    key: "generation",
    dataIndex: "generation",
  },

  {
    title: "收样日期",
    key: "receivedDate",
    dataIndex: "receivedDate",
  },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];
const innerColumns = [
  { title: "序号", dataIndex: "id", key: "id" },
  { title: "样品编号", dataIndex: "sampleCode", key: "sampleCode" },
  {
    title: "批号/编号",
    key: "batchNumber",
    dataIndex: "batchNumber",

    // slots: { customRender: "batchNumber" },
  },
  {
    title: "图片",
    dataIndex: "picture",
    key: "picture",
    slots: { customRender: "picture" },
  },
  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];

export default defineComponent({
  props: ["sample"],
  setup(props, ctx) {
    const goDetail = function (detail: any) {
      ctx.emit("routerSamplate", detail);
    };
    const goUpdate = function (detail: any) {
      ctx.emit("routerSampleUpdate", detail);
    };

    const downloadTag = function (id: number) {
      DownLoadSample(id);
    };
    return {
      columns,
      goDetail,
      goUpdate,
      innerColumns,
      base,
      downloadTag,
    };
  },
  components: {
    SmileOutlined,
    DownOutlined,
  },
});
