
import {
  defineComponent,
  ref,
  onMounted,
  toRaw,
  reactive,
  watch,
  toRefs,
} from "vue";
import SampleTable from "../../../components/ATestdetection/SampleSearch/SampleTable.vue";

import {
  getSampleList,
  get_sample_product_name,
} from "../../../server/http/api/user";
import { getTime } from "@/utils/setData";

import { useRouter } from "vue-router";
export default defineComponent({
  name: "SampleSearch",
  components: { SampleTable },
  setup() {
    const sample: any = ref([]);
    const productName: any = ref([]);
    const router = useRouter();
    let total = ref(0);
    const formState: any = reactive({
      productId: null,
      manufacturer: "",
      receivedDate: [],
      pageNum: 1,
      pageSize: 10,
    });
    function searchList() {
      if (
        formState.receivedDate !== null &&
        formState.receivedDate.length !== 0
      ) {
        //console.log(formState.receivedDate);

        getSampleList({
          productId: formState.productId,
          manufacturer: formState.manufacturer,
          receivedDate:
            getTime(formState.receivedDate[0]) +
            "~" +
            getTime(formState.receivedDate[1]),
          pageNum: formState.pageNum,
          pageSize: formState.pageSize,
        }).then((res: any) => {
          sample.value = res.data.data.list;
          total.value = res.data.data.total;
        });
      } else {
        getSampleList({
          productId: formState.productId,
          manufacturer: formState.manufacturer,
          receivedDate: null,
          pageNum: formState.pageNum,
          pageSize: formState.pageSize,
        }).then((res: any) => {
          sample.value = res.data.data.list;
          total.value = res.data.data.total;
        });
      }
    }
    watch(
      formState,
      () => {
        //console.log(123);

        searchList();
      },
      {
        immediate: true,
      }
    );

    const routerSamplate = function (detail: any) {
      //console.log(detail);
      router.push({
        name: "sampleDetail",
        params: { detail: JSON.stringify(detail) },
      });
    };
    // 修改
    const routerSampleUpdate = function (detail: any) {
      router.push({
        name: "SampleUpdate",
        params: { insertFlag: detail.insertFlag },
      });
    };
    // 产品检测项
    get_sample_product_name().then((res: any) => {
      if (res.data.code === 200) {
        productName.value = res.data.data;
      }
    });
    return {
      routerSampleUpdate,
      ...toRefs(formState),
      sample,
      routerSamplate,
      productName,
      total,
    };
  },
});
